package com.blissless.tensei.streamimport android.os.Bundleimport android.os.Handlerimport android.os.Looperimport android.view.TextureViewimport android.widget.FrameLayoutimport androidx.activity.ComponentActivityimport androidx.activity.compose.setContentimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.clickableimport androidx.compose.foundation.layout.*import androidx.compose.foundation.lazy.LazyRowimport androidx.compose.foundation.lazy.itemsIndexedimport androidx.compose.foundation.shape.RoundedCornerShapeimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.automirrored.filled.ArrowBackimport androidx.compose.material.icons.filled.Pauseimport androidx.compose.material.icons.filled.PlayArrowimport androidx.compose.material.icons.filled.Settingsimport androidx.compose.material.icons.filled.Subtitlesimport androidx.compose.material.icons.automirrored.filled.VolumeUpimport androidx.compose.material3.*import androidx.compose.runtime.*import androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.graphics.vector.ImageVectorimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dpimport androidx.compose.ui.unit.spimport androidx.compose.ui.viewinterop.AndroidViewimport androidx.media3.common.Cimport androidx.media3.common.MediaItemimport androidx.media3.common.Playerimport androidx.media3.common.VideoSizeimport androidx.media3.common.text.Cueimport androidx.media3.common.text.CueGroupimport androidx.media3.datasource.okhttp.OkHttpDataSourceimport androidx.media3.exoplayer.ExoPlayerimport androidx.media3.exoplayer.source.DefaultMediaSourceFactoryimport androidx.media3.ui.AspectRatioFrameLayoutimport androidx.media3.ui.SubtitleViewimport eu.kanade.tachiyomi.animesource.model.Trackimport eu.kanade.tachiyomi.animesource.model.Videoimport kotlinx.coroutines.delayimport kotlinx.coroutines.launchimport okhttp3.OkHttpClientimport java.util.concurrent.TimeUnitclass PlayerActivity : ComponentActivity() {    private var player: ExoPlayer? = null    private var videoContainer: AspectRatioFrameLayout? = null    private var subtitleView: SubtitleView? = null    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        val videos = PlayerData.videos.toList()        val startQuality = PlayerData.currentQualityIndex.coerceIn(0, videos.lastIndex)        var currentVideo by mutableStateOf(videos.getOrNull(startQuality))        var showOverlay by mutableStateOf(true)        var showQualitySheet by mutableStateOf(false)        var showSubSheet by mutableStateOf(false)        var showAudioSheet by mutableStateOf(false)        var selectedSubtitle by mutableStateOf(PlayerData.selectedSubtitle)        var selectedAudio by mutableStateOf(PlayerData.selectedAudio)        var isPlaying by mutableStateOf(true)        var adaptiveMode by mutableStateOf(false)        var playbackPosition by mutableLongStateOf(0L)        var playbackDuration by mutableLongStateOf(0L)        val handler = Handler(Looper.getMainLooper())        val hideOverlay = Runnable { showOverlay = false }        fun scheduleHide() {            handler.removeCallbacks(hideOverlay)            handler.postDelayed(hideOverlay, 3000L)        }        fun formatTime(ms: Long): String {            val totalSec = ms / 1000            return "%02d:%02d".format(totalSec / 60, totalSec % 60)        }        fun buildMediaItem(video: Video, subtitle: Track?): MediaItem {            val builder = MediaItem.Builder()                .setUri(android.net.Uri.parse(video.videoUrl))            builder.setMediaMetadata(                    androidx.media3.common.MediaMetadata.Builder()                        .setTitle(PlayerData.animeTitle)                        .setSubtitle(video.videoTitle)                        .build()                )            subtitle?.let { track ->                val mime = when {                    track.url.contains(".vtt") -> "text/vtt"                    track.url.contains(".srt") -> "application/x-subrip"                    else -> "text/vtt"                }                builder.setSubtitleConfigurations(                    listOf(                        MediaItem.SubtitleConfiguration.Builder(android.net.Uri.parse(track.url))                            .setMimeType(mime)                            .setLanguage(track.lang)                            .setSelectionFlags(C.SELECTION_FLAG_DEFAULT or C.SELECTION_FLAG_AUTOSELECT)                            .build()                    )                )            }            return builder.build()        }        fun playVideo(video: Video) {            currentVideo = video            val mediaItem = buildMediaItem(video, selectedSubtitle)            val pos = player?.currentPosition ?: 0L            player?.let { p ->                p.stop()                p.clearMediaItems()                p.setMediaItem(mediaItem)                if (pos > 0) p.seekTo(pos)                p.prepare()                p.playWhenReady = true            }            PlayerData.currentQualityIndex = videos.indexOf(video).coerceAtLeast(0)        }        val extClient = PlayerData.extensionClient        val firstVideo = videos.getOrNull(startQuality)        player = if (extClient != null) {            val dsFactory = OkHttpDataSource.Factory(extClient)            firstVideo?.headers?.let { h ->                val props = (0 until h.size).associate { h.name(it) to h.value(it) }                dsFactory.setDefaultRequestProperties(props)            }            val msFactory = DefaultMediaSourceFactory(this).setDataSourceFactory(dsFactory)            ExoPlayer.Builder(this).setMediaSourceFactory(msFactory).build()        } else {            ExoPlayer.Builder(this).build()        }.also { exo ->            val first = videos.getOrNull(startQuality)            if (first != null) {                val mediaItemBuilder = MediaItem.Builder()                    .setUri(android.net.Uri.parse(first.videoUrl))                // Add subtitle config                val sub = PlayerData.selectedSubtitle                if (sub != null) {                    val subMime = when {                        sub.url.contains(".vtt") -> "text/vtt"                        sub.url.contains(".srt") -> "application/x-subrip"                        else -> "text/vtt"                    }                    val subConfig = MediaItem.SubtitleConfiguration.Builder(android.net.Uri.parse(sub.url))                        .setMimeType(subMime)                        .setLanguage(sub.lang)                        .setSelectionFlags(C.SELECTION_FLAG_DEFAULT or C.SELECTION_FLAG_AUTOSELECT)                        .build()                    mediaItemBuilder.setSubtitleConfigurations(listOf(subConfig))                }                val mediaItem = mediaItemBuilder.build()                exo.setMediaItem(mediaItem)                exo.prepare()                exo.playWhenReady = true            }            exo.addListener(object : Player.Listener {                override fun onPlaybackStateChanged(playbackState: Int) {                    if (playbackState == Player.STATE_READY) {                        isPlaying = exo.playWhenReady                    }                }                override fun onIsPlayingChanged(it: Boolean) {                    isPlaying = it                }                override fun onPlayerError(error: androidx.media3.common.PlaybackException) {                }                override fun onPlayerErrorChanged(error: androidx.media3.common.PlaybackException?) {                }                override fun onVideoSizeChanged(videoSize: VideoSize) {                    val ratio = if (videoSize.width == 0 || videoSize.height == 0) 0f                    else {                        var r = videoSize.width.toFloat() / videoSize.height.toFloat() * videoSize.pixelWidthHeightRatio                        @Suppress("DEPRECATION") if (videoSize.unappliedRotationDegrees == 90 || videoSize.unappliedRotationDegrees == 270) {                            r = 1f / r                        }                        r                    }                    videoContainer?.setAspectRatio(ratio)                }                @Deprecated("Use onCues(CueGroup) instead", ReplaceWith("onCues(CueGroup(cues))"))                override fun onCues(cues: List<Cue>) {                    subtitleView?.setCues(cues)                }                override fun onCues(cueGroup: CueGroup) {                    subtitleView?.setCues(cueGroup.cues)                }            })        }        setContent {            MaterialTheme(colorScheme = darkColorScheme()) {                Box(modifier = Modifier.fillMaxSize()) {                    AndroidView(                        modifier = Modifier.fillMaxSize(),                        factory = { ctx ->                            val container = AspectRatioFrameLayout(ctx).apply {                                resizeMode = AspectRatioFrameLayout.RESIZE_MODE_FIT                                setBackgroundColor(android.graphics.Color.BLACK)                            }                            val textureView = TextureView(ctx)                            container.addView(textureView, FrameLayout.LayoutParams(                                FrameLayout.LayoutParams.MATCH_PARENT,                                FrameLayout.LayoutParams.MATCH_PARENT                            ))                            val subView = SubtitleView(ctx).apply {                                setUserDefaultStyle()                                setUserDefaultTextSize()                            }                            subtitleView = subView                            container.addView(subView, FrameLayout.LayoutParams(                                FrameLayout.LayoutParams.MATCH_PARENT,                                FrameLayout.LayoutParams.MATCH_PARENT                            ))                            player?.setVideoTextureView(textureView)                            videoContainer = container                            container.setOnClickListener { showOverlay = true; scheduleHide() }                            container                        }                    )                    LaunchedEffect(player) {                        while (true) {                            delay(200)                            playbackPosition = player?.currentPosition ?: 0L                            playbackDuration = player?.duration ?: 0L                        }                    }                    if (showOverlay) {                        Column(                            modifier = Modifier                                .fillMaxSize()                                .background(Color(0x80000000))                                .clickable { showOverlay = true; scheduleHide() }                                .padding(16.dp)                        ) {                            Row(                                modifier = Modifier.fillMaxWidth(),                                horizontalArrangement = Arrangement.SpaceBetween,                                verticalAlignment = Alignment.CenterVertically                            ) {                                IconButton(onClick = { finish() }) {                                    Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back", tint = Color.White)                                }                                Text(                                    PlayerData.animeTitle,                                    color = Color.White,                                    fontWeight = FontWeight.Bold,                                    maxLines = 1,                                    overflow = TextOverflow.Ellipsis,                                    modifier = Modifier.weight(1f)                                )                            }                            Spacer(modifier = Modifier.weight(1f))                            SeekBarSection(                                position = playbackPosition,                                duration = playbackDuration,                                formatTime = ::formatTime,                                onSeek = { pos -> player?.seekTo(pos) }                            )                            Spacer(modifier = Modifier.height(16.dp))                            if (showQualitySheet) {                                QualitySheet(                                    videos = videos,                                    currentIndex = PlayerData.currentQualityIndex,                                    adaptiveMode = adaptiveMode,                                    onSelect = { idx ->                                        showQualitySheet = false; playVideo(videos[idx])                                    },                                    onToggleAdaptive = { adaptiveMode = !adaptiveMode },                                    onDismiss = { showQualitySheet = false }                                )                            }                            if (showSubSheet) {                                SubtitleSheet(                                    tracks = currentVideo?.subtitleTracks ?: emptyList(),                                    selected = selectedSubtitle,                                    onSelect = { track ->                                        showSubSheet = false                                        selectedSubtitle = track                                        PlayerData.selectedSubtitle = track                                        currentVideo?.let { playVideo(it) }                                    },                                    onDismiss = { showSubSheet = false }                                )                            }                            if (showAudioSheet) {                                AudioSheet(                                    tracks = currentVideo?.audioTracks ?: emptyList(),                                    selected = selectedAudio,                                    onSelect = { track ->                                        showAudioSheet = false                                        selectedAudio = track                                        PlayerData.selectedAudio = track                                        currentVideo?.let { playVideo(it) }                                    },                                    onDismiss = { showAudioSheet = false }                                )                            }                            Row(                                modifier = Modifier.fillMaxWidth(),                                horizontalArrangement = Arrangement.SpaceEvenly                            ) {                                ControlChip(                                    icon = Icons.Default.Settings,                                    label = "Quality",                                    onClick = { showQualitySheet = !showQualitySheet; showSubSheet = false; showAudioSheet = false; scheduleHide() }                                )                                if ((currentVideo?.subtitleTracks?.size ?: 0) > 0) {                                    ControlChip(                                        icon = Icons.Default.Subtitles,                                        label = selectedSubtitle?.lang?.uppercase() ?: "Subs",                                        onClick = { showSubSheet = !showSubSheet; showQualitySheet = false; showAudioSheet = false; scheduleHide() }                                    )                                }                                if ((currentVideo?.audioTracks?.size ?: 0) > 0) {                                    ControlChip(                                        icon = Icons.AutoMirrored.Filled.VolumeUp,                                        label = selectedAudio?.lang?.uppercase() ?: "Audio",                                        onClick = { showAudioSheet = !showAudioSheet; showQualitySheet = false; showSubSheet = false; scheduleHide() }                                    )                                }                            }                            Spacer(modifier = Modifier.height(16.dp))                            Row(                                modifier = Modifier.fillMaxWidth(),                                horizontalArrangement = Arrangement.Center                            ) {                                IconButton(onClick = {                                    player?.let { p ->                                        if (p.isPlaying) p.pause() else p.play()                                    }                                }) {                                    Icon(                                        if (isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,                                        contentDescription = "Play/Pause",                                        tint = Color.White,                                        modifier = Modifier.size(48.dp)                                    )                                }                            }                        }                    }                }            }        }        scheduleHide()    }    override fun onStop() {        super.onStop()        player?.pause()    }    override fun onDestroy() {        super.onDestroy()        player?.release()        player = null        PlayerData.videos = emptyList()    }}@Composableprivate fun SeekBarSection(    position: Long,    duration: Long,    formatTime: (Long) -> String,    onSeek: (Long) -> Unit,) {    Column(modifier = Modifier.fillMaxWidth().padding(horizontal = 8.dp)) {        Slider(            value = if (duration > 0) (position.toFloat() / duration.toFloat()).coerceIn(0f, 1f) else 0f,            onValueChange = { onSeek((it * duration).toLong()) },            colors = SliderDefaults.colors(                thumbColor = Color.White,                activeTrackColor = Color.White,                inactiveTrackColor = Color(0x66FFFFFF),            ),        )        Row(            modifier = Modifier.fillMaxWidth().padding(horizontal = 4.dp),            horizontalArrangement = Arrangement.SpaceBetween        ) {            Text(formatTime(position), color = Color.White, fontSize = 12.sp)            Text(formatTime(duration), color = Color.White, fontSize = 12.sp)        }    }}@Composableprivate fun ControlChip(icon: ImageVector, label: String, onClick: () -> Unit) {    Surface(        onClick = onClick,        shape = RoundedCornerShape(20.dp),        color = Color(0xCCFFFFFF),        modifier = Modifier.height(40.dp)    ) {        Row(            modifier = Modifier.padding(horizontal = 12.dp),            verticalAlignment = Alignment.CenterVertically,            horizontalArrangement = Arrangement.spacedBy(4.dp)        ) {            Icon(icon, contentDescription = null, tint = Color.Black, modifier = Modifier.size(18.dp))            Text(label, color = Color.Black, fontSize = 13.sp, fontWeight = FontWeight.Medium)        }    }}@Composableprivate fun QualitySheet(    videos: List<Video>,    currentIndex: Int,    adaptiveMode: Boolean,    onSelect: (Int) -> Unit,    onToggleAdaptive: () -> Unit,    onDismiss: () -> Unit) {    Card(        modifier = Modifier.fillMaxWidth().padding(bottom = 8.dp),        colors = CardDefaults.cardColors(containerColor = Color(0xEE333333))    ) {        Column(modifier = Modifier.padding(12.dp)) {            Text("Quality", color = Color.White, fontWeight = FontWeight.Bold)            Spacer(modifier = Modifier.height(4.dp))            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {                FilterChip(                    selected = adaptiveMode,                    onClick = onToggleAdaptive,                    label = { Text("Auto") },                    colors = FilterChipDefaults.filterChipColors(                        selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                    )                )                LazyRow(horizontalArrangement = Arrangement.spacedBy(6.dp)) {                    itemsIndexed(videos) { idx, v ->                        val label = if (v.resolution != null && v.resolution > 0) "${v.resolution}p"                                     else v.videoTitle.ifEmpty { "Q$idx" }                        FilterChip(                            selected = !adaptiveMode && idx == currentIndex,                            onClick = { onSelect(idx) },                            label = { Text(label) },                            colors = FilterChipDefaults.filterChipColors(                                selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                            )                        )                    }                }            }        }    }}@Composableprivate fun SubtitleSheet(tracks: List<Track>, selected: Track?, onSelect: (Track?) -> Unit, onDismiss: () -> Unit) {    Card(        modifier = Modifier.fillMaxWidth().padding(bottom = 8.dp),        colors = CardDefaults.cardColors(containerColor = Color(0xEE333333))    ) {        Column(modifier = Modifier.padding(12.dp)) {            Text("Subtitles", color = Color.White, fontWeight = FontWeight.Bold)            Spacer(modifier = Modifier.height(4.dp))            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {                FilterChip(                    selected = selected == null,                    onClick = { onSelect(null) },                    label = { Text("Off") },                    colors = FilterChipDefaults.filterChipColors(                        selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                    )                )                tracks.forEach { track ->                    FilterChip(                        selected = selected == track,                        onClick = { onSelect(track) },                        label = { Text(track.lang.uppercase()) },                        colors = FilterChipDefaults.filterChipColors(                            selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                        )                    )                }            }        }    }}@Composableprivate fun AudioSheet(tracks: List<Track>, selected: Track?, onSelect: (Track?) -> Unit, onDismiss: () -> Unit) {    Card(        modifier = Modifier.fillMaxWidth().padding(bottom = 8.dp),        colors = CardDefaults.cardColors(containerColor = Color(0xEE333333))    ) {        Column(modifier = Modifier.padding(12.dp)) {            Text("Audio", color = Color.White, fontWeight = FontWeight.Bold)            Spacer(modifier = Modifier.height(4.dp))            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {                FilterChip(                    selected = selected == null,                    onClick = { onSelect(null) },                    label = { Text("Default") },                    colors = FilterChipDefaults.filterChipColors(                        selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                    )                )                tracks.forEach { track ->                    FilterChip(                        selected = selected == track,                        onClick = { onSelect(track) },                        label = { Text(track.lang.uppercase()) },                        colors = FilterChipDefaults.filterChipColors(                            selectedContainerColor = Color(0xFF1976D2), selectedLabelColor = Color.White                        )                    )                }            }        }    }}